import { type ComponentType } from 'react';

import {
  ArrowSmallDownRightIcon,
  ArrowSmallRightIcon,
  ArrowSmallUpRightIcon,
} from '@dynatrace/strato-icons';

import { iconStyles } from './Icon.sty.js';
import type { TrendDirection } from '../types/trend-direction.js';

interface TrendIconProps {
  direction: TrendDirection;
  color: string;
}

export const Icon = ({ direction, color }: TrendIconProps) => {
  const iconMap: Record<TrendDirection, ComponentType> = {
    upward: ArrowSmallUpRightIcon,
    downward: ArrowSmallDownRightIcon,
    neutral: ArrowSmallRightIcon,
  };

  const Icon = iconMap[direction] ?? ArrowSmallRightIcon;

  return (
    <div className={iconStyles} style={{ color }}>
      <Icon />
    </div>
  );
};
